const https = require('https');
const fs = require('fs');

https.get('https://cdn.discordapp.com/attachments/1286499284467847238/1482101372345385153/benessa.mp4?ex=69b5b9f7&is=69b46877&hm=cb26d05e1f2d29d030c8461c58fa94c1169e24d29a104c643c769ff7474c02f4&', (res) => {
  const file = fs.createWriteStream('vid.mp4');
  res.pipe(file);
  file.on('finish', () => {
    file.close();
    console.log('done');
  });
});